@dataclass
class TravelParams:
    """Travel parameters from CLI."""
    align_time: float
    top_speed: float
    warp_speed: float
    dock_time: float
    gate_time: float


@dataclass
class ShipConfig:
    """Ship configuration from config file."""
    name: str
    type: str  # Deep Space Transport, Blockade Runner, Freighter
    align_time: float
    top_speed: float
    warp_speed: float
    cargo_size: int


@dataclass
class TimesConfig:
    """Times configuration from config file."""
    dock: float
    gate: float
    move_cargo: float


@dataclass
class Config:
    """Full configuration."""
    ships: Dict[str, ShipConfig]
    times: TimesConfig


@dataclass
class Waypoint:
    """A waypoint in the manifest."""
    name: str
    cargo: Optional[float]


@dataclass
class Manifest:
    """Cargo manifest."""
    start_cargo: Optional[float]
    waypoints: List[Waypoint]


@dataclass
class CargoOperation:
    """A cargo operation at a location."""
    location: str
    action: str  # 'load' or 'unload'
    amount: float


@dataclass
class Trip:
    """A single trip with cargo."""
    start_location: str
    end_location: str
    start_cargo: float
    operations: List[CargoOperation]  # Operations at end location

